import{_ as a,o as t,c as o,a4 as i}from"./chunks/framework.CKa9pyC8.js";const u=JSON.parse('{"title":"Notely Feature Reference","description":"","frontmatter":{},"headers":[],"relativePath":"feature-reference.md","filePath":"feature-reference.md","lastUpdated":1784636841000}'),r={name:"feature-reference.md"};function n(s,e,l,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="notely-feature-reference" tabindex="-1">Notely Feature Reference <a class="header-anchor" href="#notely-feature-reference" aria-label="Permalink to &quot;Notely Feature Reference&quot;">​</a></h1><p>This page explains every major user-facing feature in Notely.</p><h2 id="_1-notes-and-workspace" tabindex="-1">1. Notes and Workspace <a class="header-anchor" href="#_1-notes-and-workspace" aria-label="Permalink to &quot;1. Notes and Workspace&quot;">​</a></h2><h3 id="workspace-selection" tabindex="-1">Workspace selection <a class="header-anchor" href="#workspace-selection" aria-label="Permalink to &quot;Workspace selection&quot;">​</a></h3><p>Use <strong>File -&gt; Open Workspace</strong> to choose the folder where your notes are stored.</p><p>Use <strong>File -&gt; Open Recent</strong> to reopen a recently used workspace quickly.</p><h3 id="opening-the-workspace-externally" tabindex="-1">Opening the workspace externally <a class="header-anchor" href="#opening-the-workspace-externally" aria-label="Permalink to &quot;Opening the workspace externally&quot;">​</a></h3><p>On the landing screen, the <strong>File</strong> menu exposes two shortcuts for working with the workspace folder outside Notely:</p><ul><li><strong>File -&gt; Open Workspace in VS Code</strong> (<code>Ctrl/Cmd + Shift + O</code>) — opens the active workspace folder directly in VS Code. Falls back to the system default app if VS Code is not installed.</li><li><strong>File -&gt; Reveal Workspace in File Explorer</strong> (<code>Ctrl/Cmd + Shift + J</code>) — opens the workspace folder in the native system file browser.</li></ul><h3 id="opening-the-website-view" tabindex="-1">Opening the website view <a class="header-anchor" href="#opening-the-website-view" aria-label="Permalink to &quot;Opening the website view&quot;">​</a></h3><p>The <strong>Web</strong> menu provides quick access to the rendered website output:</p><ul><li><strong>Web -&gt; Open Current Note Website View</strong> (<code>Ctrl/Cmd + Shift + W</code>) — available when a note is open; renders the current note as a website preview in the default browser.</li><li><strong>Web -&gt; Open Project Website</strong> (<code>Ctrl/Cmd + Shift + W</code>) — available on the landing screen; opens the project website.</li></ul><h3 id="project-aware-workspace" tabindex="-1">Project-aware workspace <a class="header-anchor" href="#project-aware-workspace" aria-label="Permalink to &quot;Project-aware workspace&quot;">​</a></h3><p>You can keep notes grouped by project while still working inside one larger workspace.</p><h3 id="landing-dashboard" tabindex="-1">Landing dashboard <a class="header-anchor" href="#landing-dashboard" aria-label="Permalink to &quot;Landing dashboard&quot;">​</a></h3><p>The landing view includes lightweight workspace overview panels so you can resume work quickly:</p><ul><li><strong>Continue Writing</strong> shows the single most recently edited note so you can resume immediately.</li><li><strong>Recent Notes</strong> shows recently changed documents.</li><li><strong>Favorites</strong> collects starred notes.</li><li><strong>Open Tasks</strong> surfaces unchecked tasks across the workspace.</li></ul><h3 id="note-and-folder-creation" tabindex="-1">Note and folder creation <a class="header-anchor" href="#note-and-folder-creation" aria-label="Permalink to &quot;Note and folder creation&quot;">​</a></h3><ul><li>Create notes from <strong>File -&gt; New Note</strong> (<code>Ctrl/Cmd + N</code>).</li><li>Create folders to group related notes.</li><li>Customize the icon and color of any folder or note by right-clicking it and selecting &quot;Customize icon &amp; color...&quot; or from the context menu in the open tabs.</li><li>Rename and delete notes from list actions.</li></ul><h3 id="trash-recovery-bin" tabindex="-1">Trash Recovery Bin <a class="header-anchor" href="#trash-recovery-bin" aria-label="Permalink to &quot;Trash Recovery Bin&quot;">​</a></h3><p>When folders or notes are deleted, they are moved to a temporary Trash Bin instead of being permanently erased immediately. The Trash Bin recovery drawer (<code>Trash</code> quick action on the landing view) supports:</p><ul><li>Browsing deleted files and folders with their deletion timestamps.</li><li>Restoring items back to their original paths.</li><li>Permanently emptying the trash bin to free up disk space.</li></ul><h2 id="_2-editor-and-writing-experience" tabindex="-1">2. Editor and Writing Experience <a class="header-anchor" href="#_2-editor-and-writing-experience" aria-label="Permalink to &quot;2. Editor and Writing Experience&quot;">​</a></h2><h3 id="multiple-edit-modes" tabindex="-1">Multiple edit modes <a class="header-anchor" href="#multiple-edit-modes" aria-label="Permalink to &quot;Multiple edit modes&quot;">​</a></h3><ul><li><strong>Edit</strong>: write markdown source.</li><li><strong>Split</strong>: source and preview side-by-side.</li><li><strong>Preview</strong>: read-only rendered output.</li><li><strong>Web Preview</strong>: richer rendering for selected notes.</li></ul><h3 id="markdown-toolbar" tabindex="-1">Markdown toolbar <a class="header-anchor" href="#markdown-toolbar" aria-label="Permalink to &quot;Markdown toolbar&quot;">​</a></h3><p>Quick insert actions for headings, emphasis, lists, links, tables, diagrams, and validation.</p><h3 id="inline-table-editor" tabindex="-1">Inline table editor <a class="header-anchor" href="#inline-table-editor" aria-label="Permalink to &quot;Inline table editor&quot;">​</a></h3><p>When the cursor is inside a markdown table, Notely opens an inline table editor overlay with focused controls:</p><ul><li>Edit headers and cells in a grid view.</li><li>Add/remove rows and columns from contextual action chips.</li><li>Set per-column alignment (left, center, right) from header actions.</li><li>Save and cancel explicitly from compact top controls.</li><li>Background page scrolling is locked while editing to keep interaction scoped to the table editor.</li></ul><h3 id="code-blocks" tabindex="-1">Code Blocks <a class="header-anchor" href="#code-blocks" aria-label="Permalink to &quot;Code Blocks&quot;">​</a></h3><p>Notely provides a rich experience for working with code snippets:</p><ul><li><strong>Auto-detection</strong>: Paste a snippet without a language tag and Notely will automatically detect it (e.g., JavaScript, Python, HTML).</li><li><strong>Auto-formatting</strong>: Use the 🪄 Format button in the preview hover toolbar or inside the editor to instantly auto-indent and format your code using Prettier.</li><li><strong>Dedicated Editor</strong>: Click the ✎ Edit button on any code block in Preview mode to open a distraction-free Code Editor popup with syntax highlighting, search, and language selection.</li><li><strong>Code Execution</strong>: Click the ▶ Run button in the hover toolbar or inside the popup editor to execute JavaScript (<code>js</code>, <code>javascript</code>) and Python (<code>py</code>, <code>python</code>) snippets locally. Output is displayed in an integrated high-contrast dark terminal output drawer (with exit status and a &quot;Clear&quot; button). Execution times out automatically after 10 seconds to prevent hanging. For other languages, the run button is disabled with a helpful tooltip.</li></ul><h3 id="find-and-replace" tabindex="-1">Find and replace <a class="header-anchor" href="#find-and-replace" aria-label="Permalink to &quot;Find and replace&quot;">​</a></h3><p>Search inside the current note and jump through results quickly.</p><h3 id="outline-navigation" tabindex="-1">Outline navigation <a class="header-anchor" href="#outline-navigation" aria-label="Permalink to &quot;Outline navigation&quot;">​</a></h3><p>Use <strong>View -&gt; Show Outline</strong> to jump between sections in long notes.</p><h3 id="focus-mode" tabindex="-1">Focus mode <a class="header-anchor" href="#focus-mode" aria-label="Permalink to &quot;Focus mode&quot;">​</a></h3><p>Use <strong>View -&gt; Focus Mode</strong> to reduce visual distractions.</p><h3 id="terminal-and-workspace-tools" tabindex="-1">Terminal and workspace tools <a class="header-anchor" href="#terminal-and-workspace-tools" aria-label="Permalink to &quot;Terminal and workspace tools&quot;">​</a></h3><p>Use <strong>View -&gt; Show Terminal</strong> to open the embedded terminal.</p><p>Use <strong>View -&gt; Terminal Shell</strong> to switch between Auto, Bash, and CMD.</p><p>Use <strong>Workspace -&gt; Workspace Activity</strong> to review recent changes across the active workspace.</p><h3 id="appearance-and-layout" tabindex="-1">Appearance and layout <a class="header-anchor" href="#appearance-and-layout" aria-label="Permalink to &quot;Appearance and layout&quot;">​</a></h3><p>Notely includes view and appearance controls for different working styles:</p><ul><li><strong>Settings -&gt; Theme</strong>: System, Light, or Dark</li><li><strong>View -&gt; Tile Notes / Table Notes</strong>: landing list layout</li><li><strong>View -&gt; Comfortable Density / Compact Density</strong>: landing list density</li><li><strong>View -&gt; Zoom In / Zoom Out / Reset Zoom</strong>: app-scale display controls</li></ul><h3 id="note-statistics" tabindex="-1">Note statistics <a class="header-anchor" href="#note-statistics" aria-label="Permalink to &quot;Note statistics&quot;">​</a></h3><p>When editing a note, the status bar displays:</p><ul><li><strong>Word count</strong>: Live count of words in the active tab content (updates as you type).</li><li><strong>Line count</strong>: Total number of lines in the document.</li><li><strong>Reading time</strong>: Estimated reading time in minutes (calculated at 200 words per minute).</li></ul><p>Statistics update independently for Raw and Formal editing modes.</p><h3 id="copy-and-export" tabindex="-1">Copy and export <a class="header-anchor" href="#copy-and-export" aria-label="Permalink to &quot;Copy and export&quot;">​</a></h3><p>Export note content in different formats directly from the toolbar:</p><ul><li><strong>Copy as HTML</strong>: copies a nicely formatted version you can paste into other apps</li><li><strong>Copy as Plain Text</strong>: copies the plain note text</li></ul><p>Both actions show success or error feedback via notifications.</p><h3 id="breadcrumb-navigation" tabindex="-1">Breadcrumb navigation <a class="header-anchor" href="#breadcrumb-navigation" aria-label="Permalink to &quot;Breadcrumb navigation&quot;">​</a></h3><p>The editor displays a breadcrumb trail showing the full folder hierarchy leading to the current note:</p><ul><li>Click any segment to navigate to that folder.</li><li>Helps you keep track of where the current note lives.</li><li>Updates dynamically when you switch notes.</li></ul><h2 id="_3-quality-and-validation" tabindex="-1">3. Quality and Validation <a class="header-anchor" href="#_3-quality-and-validation" aria-label="Permalink to &quot;3. Quality and Validation&quot;">​</a></h2><h3 id="markdown-validation" tabindex="-1">Markdown validation <a class="header-anchor" href="#markdown-validation" aria-label="Permalink to &quot;Markdown validation&quot;">​</a></h3><p>Notely reports markdown issues while you edit.</p><h3 id="typo-checking-spelling-dictionary" tabindex="-1">Typo checking &amp; Spelling Dictionary <a class="header-anchor" href="#typo-checking-spelling-dictionary" aria-label="Permalink to &quot;Typo checking &amp; Spelling Dictionary&quot;">​</a></h3><p>Notely flags likely spelling mistakes in real-time as you write (excluding code blocks and raw markdown syntax).</p><ul><li><strong>Hunspell engine</strong>: Powered by Hunspell under the hood for accurate, high-quality dictionary checks.</li><li><strong>Ignore / Add to dictionary</strong>: Right-click on a flagged spelling error in the editor to immediately ignore the word, or click <strong>Add to dictionary</strong> to add it to your custom workspace spelling dictionary.</li><li><strong>Spelling Dictionary Manager</strong>: Open the command palette (<code>Ctrl/Cmd+P</code>) and run <strong>Manage Spelling Dictionary</strong> (or click the settings menu option) to view all custom added words, search them, remove individual words, or clear the dictionary completely.</li></ul><h3 id="quick-problem-fixing" tabindex="-1">Quick problem fixing <a class="header-anchor" href="#quick-problem-fixing" aria-label="Permalink to &quot;Quick problem fixing&quot;">​</a></h3><p>When Notely finds a problem, it shows you where it is so you can jump there quickly.</p><h2 id="_4-search-and-discovery" tabindex="-1">4. Search and Discovery <a class="header-anchor" href="#_4-search-and-discovery" aria-label="Permalink to &quot;4. Search and Discovery&quot;">​</a></h2><h3 id="global-search" tabindex="-1">Global search <a class="header-anchor" href="#global-search" aria-label="Permalink to &quot;Global search&quot;">​</a></h3><p>Search by note title, folder, details, and note content across the whole workspace.</p><h4 id="advanced-search-patterns" tabindex="-1">Advanced search patterns <a class="header-anchor" href="#advanced-search-patterns" aria-label="Permalink to &quot;Advanced search patterns&quot;">​</a></h4><p>If you know advanced search patterns, you can turn on advanced matching in global search:</p><ul><li>Click the <strong><code>.*</code></strong> button in the search bar.</li><li>Type your search pattern.</li><li>Notely checks the pattern as you type and tells you if it is invalid.</li><li>Results update as you type.</li></ul><p><strong>Example use cases:</strong></p><ul><li>Find function definitions: <code>function\\s+\\w+\\s*\\(</code></li><li>Find error patterns: <code>Error: \\[[A-Z0-9_]+\\]</code></li><li>Find API routes: <code>\\/api\\/[a-z]+</code></li><li>Find imports: <code>import\\s+\\{[\\w\\s,]+\\}</code></li></ul><h4 id="code-aware-search" tabindex="-1">Code-aware search <a class="header-anchor" href="#code-aware-search" aria-label="Permalink to &quot;Code-aware search&quot;">​</a></h4><p>Limit search results to code blocks only:</p><ul><li>Click the <strong><code>Code Blocks</code></strong> filter button in the search bar (appears alongside All, Notes, Folders, Current Note).</li><li>Search now only matches code sections inside notes.</li><li>Matches appear in code, not normal writing.</li><li>Works with or without advanced matching turned on.</li></ul><p><strong>Example use case:</strong></p><ul><li>Search for TypeScript patterns only: Select &quot;Code Blocks&quot; filter, search for <code>interface\\s+\\w+</code></li></ul><h3 id="content-snippets" tabindex="-1">Content snippets <a class="header-anchor" href="#content-snippets" aria-label="Permalink to &quot;Content snippets&quot;">​</a></h3><p>Search results show match context so you can confirm relevance before opening.</p><h3 id="workspace-graph" tabindex="-1">Workspace graph <a class="header-anchor" href="#workspace-graph" aria-label="Permalink to &quot;Workspace graph&quot;">​</a></h3><p>Open <strong>Workspace -&gt; Workspace Graph</strong> to see how notes and files connect to each other.</p><p>Graph capabilities include:</p><ul><li>Visual note-to-note link mapping</li><li>Media node visibility (images, videos, PDFs, and more)</li><li>Interactive zoom, pan, and drag</li><li>Mini-map for large workspaces</li></ul><p>When AI search data is available, the graph can also group notes that are closely related.</p><h2 id="_5-tasks-and-workflow" tabindex="-1">5. Tasks and Workflow <a class="header-anchor" href="#_5-tasks-and-workflow" aria-label="Permalink to &quot;5. Tasks and Workflow&quot;">​</a></h2><h3 id="tasks-overview" tabindex="-1">Tasks overview <a class="header-anchor" href="#tasks-overview" aria-label="Permalink to &quot;Tasks overview&quot;">​</a></h3><p>Task checkboxes from your notes appear in several places:</p><ul><li><strong>Open Tasks panel</strong>: unchecked tasks (<code>- [ ]</code>) only.</li><li><strong>All Tasks panel</strong>: open + closed tasks in one searchable list.</li><li><strong>Dashboard task summaries</strong>: quick counts and drill-down from landing widgets.</li><li><strong>Note-level task summary</strong>: open/closed snapshot for the current note.</li></ul><h3 id="open-tasks-panel" tabindex="-1">Open Tasks panel <a class="header-anchor" href="#open-tasks-panel" aria-label="Permalink to &quot;Open Tasks panel&quot;">​</a></h3><p>The Open Tasks panel collects unfinished tasks from all of your notes into one searchable list.</p><h4 id="opening-the-open-tasks-panel" tabindex="-1">Opening the Open Tasks panel <a class="header-anchor" href="#opening-the-open-tasks-panel" aria-label="Permalink to &quot;Opening the Open Tasks panel&quot;">​</a></h4><p>Open the panel using the Command Palette:</p><ul><li>Press <code>Ctrl/Cmd + K</code> to open the command palette.</li><li>Search for &quot;Open Tasks Panel&quot; (or type &quot;tasks&quot;, &quot;todos&quot;, &quot;checkboxes&quot;).</li><li>Press Enter to open.</li></ul><h4 id="using-the-open-tasks-panel" tabindex="-1">Using the Open Tasks panel <a class="header-anchor" href="#using-the-open-tasks-panel" aria-label="Permalink to &quot;Using the Open Tasks panel&quot;">​</a></h4><ul><li><strong>Filter tasks</strong>: Use the search input to filter by task text or source note title.</li><li><strong>View task count</strong>: The header shows the total number of open tasks.</li><li><strong>Group by source</strong>: Tasks stay grouped by the note they came from.</li><li><strong>Open source note</strong>: Click the &quot;Open note&quot; link next to any task to navigate to that note and close the panel.</li><li><strong>Supported task syntax</strong>: Recognizes all markdown task formats: <ul><li><code>- [ ] Task text</code> (dash)</li><li><code>* [ ] Task text</code> (asterisk)</li><li><code>+ [ ] Task text</code> (plus)</li></ul></li></ul><h3 id="all-tasks-panel" tabindex="-1">All Tasks panel <a class="header-anchor" href="#all-tasks-panel" aria-label="Permalink to &quot;All Tasks panel&quot;">​</a></h3><p>Use All Tasks when you need both open and completed work in one place.</p><ul><li>Includes open (<code>[ ]</code>) and closed (<code>[x]</code>) tasks.</li><li>Supports quick filtering and note-grouped review.</li><li>Useful for status reviews, audits, and release checklists.</li></ul><h4 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h4><ul><li>Track action items across project notes</li><li>Get a quick overview of all pending work</li><li>Find tasks by keyword without opening individual notes</li><li>Maintain accountability in team workspaces</li></ul><h2 id="_6-git-version-control-and-history" tabindex="-1">6. Git Version Control and History <a class="header-anchor" href="#_6-git-version-control-and-history" aria-label="Permalink to &quot;6. Git Version Control and History&quot;">​</a></h2><h3 id="native-git-repository" tabindex="-1">Native Git Repository <a class="header-anchor" href="#native-git-repository" aria-label="Permalink to &quot;Native Git Repository&quot;">​</a></h3><p>Notely integrates native Git versioning to track your document history. Workspaces can be initialized as Git repositories directly from the Version Control panel.</p><h3 id="compare-restore-and-tagging" tabindex="-1">Compare, Restore, and Tagging <a class="header-anchor" href="#compare-restore-and-tagging" aria-label="Permalink to &quot;Compare, Restore, and Tagging&quot;">​</a></h3><p>Open <strong>Version Control -&gt; History</strong> (<code>Ctrl/Cmd + Shift + H</code>) or click the <strong>History</strong> button in the note top bar to:</p><ul><li>Compare commits with word-level difference highlighting.</li><li>Toggle between rich <strong>Markdown Preview Mode</strong> and raw <strong>Code View</strong> for line differences.</li><li>Restore the active note to an older revision.</li><li>Add tag references to commits directly from the history timeline.</li></ul><h3 id="branch-stash-and-sync-management" tabindex="-1">Branch, Stash, and Sync Management <a class="header-anchor" href="#branch-stash-and-sync-management" aria-label="Permalink to &quot;Branch, Stash, and Sync Management&quot;">​</a></h3><p>The full <strong>Version Control Page</strong> includes tabs to switch branches, create tags, push/pull changes to remote repositories, and stash unstaged changes to keep your workspace tidy.</p><h2 id="_7-media-management" tabindex="-1">7. Media Management <a class="header-anchor" href="#_7-media-management" aria-label="Permalink to &quot;7. Media Management&quot;">​</a></h2><h3 id="image-and-file-linking" tabindex="-1">Image and file linking <a class="header-anchor" href="#image-and-file-linking" aria-label="Permalink to &quot;Image and file linking&quot;">​</a></h3><p>Add images and other files to your notes and link to them when needed.</p><h3 id="media-actions" tabindex="-1">Media actions <a class="header-anchor" href="#media-actions" aria-label="Permalink to &quot;Media actions&quot;">​</a></h3><p>Rename, replace, annotate, and open media in default apps.</p><h3 id="screen-capture-windows" tabindex="-1">Screen capture (Windows) <a class="header-anchor" href="#screen-capture-windows" aria-label="Permalink to &quot;Screen capture (Windows)&quot;">​</a></h3><p>Notely supports area-based screen capture directly from the editor.</p><ul><li>Trigger capture from the toolbar screen icon or <code>Ctrl/Cmd + Shift + S</code>.</li><li>Use Windows snip overlay to select an area.</li><li>Insert behavior is controlled by <strong>Settings -&gt; Screen Capture</strong>: <ul><li><strong>Auto Insert</strong>: captured image is inserted immediately.</li><li><strong>Review Before Insert</strong>: open review editor first, then save to insert.</li></ul></li><li>In review mode, edits are optional; you can save as-is.</li></ul><p>The toolbar capture icon shows current mode:</p><ul><li><code>A</code> = Auto Insert</li><li><code>R</code> = Review Before Insert</li></ul><h3 id="media-preview-tools" tabindex="-1">Media preview tools <a class="header-anchor" href="#media-preview-tools" aria-label="Permalink to &quot;Media preview tools&quot;">​</a></h3><p>Use zoom and media-aware preview controls to inspect assets.</p><h3 id="workspace-health-media-checks" tabindex="-1">Workspace Health media checks <a class="header-anchor" href="#workspace-health-media-checks" aria-label="Permalink to &quot;Workspace Health media checks&quot;">​</a></h3><p>Notely helps detect and manage:</p><ul><li>Missing linked files</li><li>Duplicate media</li><li>Unused media</li><li>Preview failures</li></ul><p>You can review where files are used and clean up unused items.</p><h3 id="image-annotation-and-lifecycle" tabindex="-1">Image annotation and lifecycle <a class="header-anchor" href="#image-annotation-and-lifecycle" aria-label="Permalink to &quot;Image annotation and lifecycle&quot;">​</a></h3><p>Image notes and markups are saved separately from the picture itself, so you can keep editing them later.</p><p>Those notes stay in sync when you replace, rename, or remove an image.</p><h3 id="original-image-backup-and-restore" tabindex="-1">Original image backup and restore <a class="header-anchor" href="#original-image-backup-and-restore" aria-label="Permalink to &quot;Original image backup and restore&quot;">​</a></h3><p>Before first edit, Notely stores an original image backup and allows restoring it later.</p><p>This helps recover from aggressive crops or accidental edits.</p><h2 id="_8-diagram-features" tabindex="-1">8. Diagram Features <a class="header-anchor" href="#_8-diagram-features" aria-label="Permalink to &quot;8. Diagram Features&quot;">​</a></h2><h3 id="mermaid-diagrams" tabindex="-1">Mermaid diagrams <a class="header-anchor" href="#mermaid-diagrams" aria-label="Permalink to &quot;Mermaid diagrams&quot;">​</a></h3><ul><li>Insert Mermaid blocks from the toolbar.</li><li>Write Mermaid syntax in markdown.</li><li>Render in preview modes.</li></ul><h3 id="excalidraw-diagrams" tabindex="-1">Excalidraw diagrams <a class="header-anchor" href="#excalidraw-diagrams" aria-label="Permalink to &quot;Excalidraw diagrams&quot;">​</a></h3><ul><li>Insert Excalidraw diagrams in notes.</li><li>Edit visually and save.</li><li>Re-open diagrams from preview for updates.</li><li>Convert an existing note image to an Excalidraw diagram from image right-click menu (<strong>Edit with Excalidraw</strong>).</li><li>Converted diagrams open with the original image already placed underneath so you can trace or mark it up.</li><li>Excalidraw previews have their own right-click actions.</li><li>If the diagram started from an image, you can switch back to the original image later.</li></ul><h2 id="_9-ai-assistance" tabindex="-1">9. AI Assistance <a class="header-anchor" href="#_9-ai-assistance" aria-label="Permalink to &quot;9. AI Assistance&quot;">​</a></h2><h3 id="ai-settings" tabindex="-1">AI settings <a class="header-anchor" href="#ai-settings" aria-label="Permalink to &quot;AI settings&quot;">​</a></h3><p>Set up AI services and sign-in details in <strong>AI -&gt; AI Settings</strong>.</p><p>You can set up:</p><ul><li>a writing assistant service for chat and rewriting</li><li>a separate service for smarter search and graph features</li></ul><h3 id="ai-chat-and-commands" tabindex="-1">AI chat and commands <a class="header-anchor" href="#ai-chat-and-commands" aria-label="Permalink to &quot;AI chat and commands&quot;">​</a></h3><p>Use AI for writing support, note understanding, and quick content actions.</p><h3 id="semantic-features" tabindex="-1">Semantic features <a class="header-anchor" href="#semantic-features" aria-label="Permalink to &quot;Semantic features&quot;">​</a></h3><p>When AI search data is turned on, Notely can find related notes by meaning, not just exact words.</p><h3 id="what-each-ai-service-can-do" tabindex="-1">What each AI service can do <a class="header-anchor" href="#what-each-ai-service-can-do" aria-label="Permalink to &quot;What each AI service can do&quot;">​</a></h3><p>Not every AI service supports every feature.</p><p>Notely shows capability warnings in settings when a selected provider cannot run a feature.</p><p>You can also choose which AI model to use in AI settings.</p><h3 id="ai-operation-feedback" tabindex="-1">AI operation feedback <a class="header-anchor" href="#ai-operation-feedback" aria-label="Permalink to &quot;AI operation feedback&quot;">​</a></h3><p>Longer AI actions show progress and completion messages so you know something is happening.</p><h3 id="how-recent-the-ai-search-data-is" tabindex="-1">How recent the AI search data is <a class="header-anchor" href="#how-recent-the-ai-search-data-is" aria-label="Permalink to &quot;How recent the AI search data is&quot;">​</a></h3><p>Notely shows whether its AI search data is fresh or getting old.</p><h2 id="_10-peer-to-peer-sync" tabindex="-1">10. Peer-to-Peer Sync <a class="header-anchor" href="#_10-peer-to-peer-sync" aria-label="Permalink to &quot;10. Peer-to-Peer Sync&quot;">​</a></h2><h3 id="discovery-and-pairing" tabindex="-1">Discovery and pairing <a class="header-anchor" href="#discovery-and-pairing" aria-label="Permalink to &quot;Discovery and pairing&quot;">​</a></h3><p>Pair trusted peers using invite codes from <strong>P2P -&gt; P2P Status</strong>.</p><h3 id="sync-status-and-conflicts" tabindex="-1">Sync status and conflicts <a class="header-anchor" href="#sync-status-and-conflicts" aria-label="Permalink to &quot;Sync status and conflicts&quot;">​</a></h3><p>Monitor sync progress and resolve conflicts with built-in conflict tools.</p><h3 id="security-controls" tabindex="-1">Security controls <a class="header-anchor" href="#security-controls" aria-label="Permalink to &quot;Security controls&quot;">​</a></h3><p>Trust and access controls help keep shared workspaces safer.</p><h2 id="_11-help-and-product-info" tabindex="-1">11. Help and Product Info <a class="header-anchor" href="#_11-help-and-product-info" aria-label="Permalink to &quot;11. Help and Product Info&quot;">​</a></h2><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><p>Open <strong>Help -&gt; Help Center</strong> (<code>F1</code>) for in-app help.</p><h3 id="keyboard-shortcuts" tabindex="-1">Keyboard shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard shortcuts&quot;">​</a></h3><p>Open <strong>Help -&gt; Keyboard Shortcuts</strong> (<code>Ctrl/Cmd + /</code>).</p><h3 id="about-dialog" tabindex="-1">About dialog <a class="header-anchor" href="#about-dialog" aria-label="Permalink to &quot;About dialog&quot;">​</a></h3><p>Open <strong>Help -&gt; About Notely</strong> to view app identity and version information.</p><h2 id="_12-preview-and-export" tabindex="-1">12. Preview and Export <a class="header-anchor" href="#_12-preview-and-export" aria-label="Permalink to &quot;12. Preview and Export&quot;">​</a></h2><h3 id="web-preview" tabindex="-1">Web preview <a class="header-anchor" href="#web-preview" aria-label="Permalink to &quot;Web preview&quot;">​</a></h3><p>Use Web Preview for richer rendered note viewing with media and diagram support.</p><h3 id="pdf-export" tabindex="-1">PDF export <a class="header-anchor" href="#pdf-export" aria-label="Permalink to &quot;PDF export&quot;">​</a></h3><p>Export notes to PDF using the same note preview system used inside the app.</p><p>PDF export keeps image quality options and visible image notes where possible.</p><h3 id="website-style-rendering" tabindex="-1">Website-style rendering <a class="header-anchor" href="#website-style-rendering" aria-label="Permalink to &quot;Website-style rendering&quot;">​</a></h3><p>Website-style output is designed to look close to what you see in preview.</p><h3 id="workspace-zip-export" tabindex="-1">Workspace zip export <a class="header-anchor" href="#workspace-zip-export" aria-label="Permalink to &quot;Workspace zip export&quot;">​</a></h3><p>From the landing screen, choose <strong>File -&gt; Export Workspace as Zip</strong>.</p><p>The workspace export dialog includes:</p><ul><li><strong>Export format</strong>: <ul><li>Notes as-is (markdown + assets)</li><li>PDF-only workspace bundle</li><li>Web format static package</li></ul></li><li><strong>App data toggle</strong>: include the <code>.notes-app</code> folder (off by default)</li><li><strong>Destination</strong>: browse folder and reuse remembered location</li><li><strong>Filename</strong>: default <code>notelyproject.zip</code>, editable before export</li></ul><p>This flow is intended for backups, handoff, archival snapshots, and portable workspace sharing.</p>',180)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
